__global__ void warmup_kernel() {
    double val = threadIdx.x;
    for (int i = 0; i < 100000; i++) {
        val = val * val + val;
    }
}

__global__ void sm_count_kernel(unsigned long long *timestamps) {
    unsigned long long start = clock64();

    // Some compute work to keep the SM busy
    double val = threadIdx.x;
    for (int i = 0; i < 10000; i++) {
        val = val * val + val;
    }

    unsigned long long end = clock64();
    timestamps[blockIdx.x] = start;
}

int main() {
    // Warmup phase - run for at least 500ms
    for (int i = 0; i < 10; i++) {
        warmup_kernel<<<256, 256>>>();
        cudaDeviceSynchronize();
    }

    // Setup for SM count measurement
    const int max_blocks = 256;
    unsigned long long *d_timestamps;
    cudaMalloc(&d_timestamps, max_blocks * sizeof(unsigned long long));

    // Launch kernel with enough blocks to fill all SMs
    sm_count_kernel<<<max_blocks, 256>>>(d_timestamps);
    cudaDeviceSynchronize();

    // Copy back timestamps
    unsigned long long h_timestamps[max_blocks];
    cudaMemcpy(h_timestamps, d_timestamps, max_blocks * sizeof(unsigned long long), cudaMemcpyDeviceToHost);

    // Find minimum timestamp (first block to start)
    unsigned long long min_time = -1ULL;
    for (int i = 0; i < max_blocks; i++) {
        if (h_timestamps[i] < min_time) {
            min_time = h_timestamps[i];
        }
    }

    // Count blocks that started within 1000 clock cycles of the first block
    // These are considered to be running concurrently on different SMs
    const unsigned long long threshold = 1000;
    int sm_count = 0;
    for (int i = 0; i < max_blocks; i++) {
        if (h_timestamps[i] - min_time < threshold) {
            sm_count++;
        }
    }

    cudaFree(d_timestamps);

    // Output just the SM count
    printf("%d\n", sm_count);

    return 0;
}

