#include <stdio.h>
#include <cuda_runtime.h>

#define DATA_SIZE_MB 512
#define ITERATIONS 10
#define WARMUP 3
#define BLOCK_SIZE 256
#define GRID_SIZE 256

__global__ void bandwidth_kernel(const float* input, float* output, int size) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    int stride = gridDim.x * blockDim.x;

    for (int i = idx; i < size; i += stride) {
        float val = input[i];  // Read from global memory
        output[i] = val;       // Write to global memory
    }
}

int main() {
    const size_t data_size_bytes = (size_t)DATA_SIZE_MB * 1024 * 1024;
    const int array_size = data_size_bytes / sizeof(float);

    // Allocate host memory for verification
    float *h_input = new float[array_size];
    for (int i = 0; i < array_size; i++) {
        h_input[i] = (float)i;
    }

    // Allocate device memory
    float *d_input, *d_output;
    cudaMalloc(&d_input, data_size_bytes);
    cudaMalloc(&d_output, data_size_bytes);

    // Copy data to device
    cudaMemcpy(d_input, h_input, data_size_bytes, cudaMemcpyHostToDevice);

    // Warmup
    for (int i = 0; i < WARMUP; i++) {
        bandwidth_kernel<<<GRID_SIZE, BLOCK_SIZE>>>(d_input, d_output, array_size);
    }
    cudaDeviceSynchronize();

    // Create events for timing
    cudaEvent_t start, stop;
    cudaEventCreate(&start);
    cudaEventCreate(&stop);

    // Start timing
    cudaEventRecord(start);

    // Run benchmark
    for (int i = 0; i < ITERATIONS; i++) {
        bandwidth_kernel<<<GRID_SIZE, BLOCK_SIZE>>>(d_input, d_output, array_size);
    }
    cudaEventRecord(stop);
    cudaEventSynchronize(stop);

    // Calculate elapsed time
    float milliseconds = 0;
    cudaEventElapsedTime(&milliseconds, start, stop);
    float seconds = milliseconds / 1000.0f;

    // Calculate bandwidth
    double total_bytes = 2.0 * data_size_bytes * ITERATIONS;  // read + write
    double bytes_per_second = total_bytes / seconds;

    // Output result
    printf("%.3f\n", bytes_per_second);

    // Cleanup
    delete[] h_input;
    cudaFree(d_input);
    cudaFree(d_output);
    cudaEventDestroy(start);
    cudaEventDestroy(stop);

    return 0;
}

