#include <stdio.h>
#include <algorithm>
#include <vector>

#define WARMUP_ITERATIONS 10
#define MEASURE_ITERATIONS 5
#define BLOCKS 256
#define THREADS 256
#define FMA_ITERATIONS 10000

__global__ void warmup_kernel(float *data) {
    float a = threadIdx.x;
    float b = blockIdx.x;
    float c = 0.0f;

    // Heavy FMA workload for warmup
    for (int i = 0; i < FMA_ITERATIONS * 10; i++) {
        c = fmaf(a, b, c);
        a = fmaf(b, c, a);
        b = fmaf(c, a, b);
    }

    // Prevent optimization
    if (c < 0.0f) {
        data[0] = c; // Never happens
    }
}

__global__ void measure_kernel(float *data, unsigned long long *clock_counts) {
    unsigned long long start_clock = clock64();

    float a = threadIdx.x;
    float b = blockIdx.x;
    float c = 0.0f;

    // Compute-intensive FMA workload
    for (int i = 0; i < FMA_ITERATIONS; i++) {
        c = fmaf(a, b, c);
        a = fmaf(b, c, a);
        b = fmaf(c, a, b);
    }

    unsigned long long end_clock = clock64();

    // Store results and prevent optimization
    if (threadIdx.x == 0 && blockIdx.x == 0) {
        clock_counts[0] = start_clock;
        clock_counts[1] = end_clock;
        if (c < 0.0f) {
            data[0] = c; // Never happens
        }
    }
}

int main() {
    float *d_data;
    unsigned long long *d_clock;
    cudaEvent_t start, stop;
    std::vector<double> frequencies;

    // Allocate device memory
    cudaMalloc(&d_data, sizeof(float));
    cudaMalloc(&d_clock, 2 * sizeof(unsigned long long));
    cudaEventCreate(&start);
    cudaEventCreate(&stop);

    // Warm-up phase - run for at least 500ms to reach boost clock
    for (int i = 0; i < WARMUP_ITERATIONS; i++) {
        warmup_kernel<<<BLOCKS, THREADS>>>(d_data);
        cudaDeviceSynchronize();
    }

    // Measurement phase
    for (int i = 0; i < MEASURE_ITERATIONS; i++) {
        cudaEventRecord(start);
        measure_kernel<<<BLOCKS, THREADS>>>(d_data, d_clock);
        cudaEventRecord(stop);
        cudaDeviceSynchronize();

        float elapsed_ms;
        cudaEventElapsedTime(&elapsed_ms, start, stop);

        unsigned long long clock_counts[2];
        cudaMemcpy(clock_counts, d_clock, 2 * sizeof(unsigned long long), cudaMemcpyDeviceToHost);

        double frequency_MHz = (double)(clock_counts[1] - clock_counts[0]) / (elapsed_ms * 1000.0);
        frequencies.push_back(frequency_MHz * 1000.0); // Convert to kHz
    }

    // Cleanup
    cudaFree(d_data);
    cudaFree(d_clock);
    cudaEventDestroy(start);
    cudaEventDestroy(stop);

    // Calculate and output median frequency in kHz
    std::sort(frequencies.begin(), frequencies.end());
    double median_frequency_kHz = frequencies[MEASURE_ITERATIONS / 2];

    // Output only the frequency in kHz as a single number
    printf("%.0f\n", median_frequency_kHz);

    return 0;
}

