__global__ void warmup_kernel() {
    double val = threadIdx.x;
    for (int i = 0; i < FMA_ITERATIONS * 100; i++) {
        val = val * val + val;
    }
}

__global__ void measure_kernel(unsigned long long *clock_counts, float *dummy) {
    unsigned long long start_clock = clock64();

    // Heavy compute to keep SMs busy
    double val = threadIdx.x;
    for (int i = 0; i < FMA_ITERATIONS; i++) {
        val = val * val + val;
    }

    unsigned long long end_clock = clock64();

    if (threadIdx.x == 0 && blockIdx.x == 0) {
        clock_counts[0] = start_clock;
        clock_counts[1] = end_clock;
        dummy[0] = (float)val; // Prevent optimization
    }
}

int main() {
    cudaEvent_t start, stop;
    cudaEventCreate(&start);
    cudaEventCreate(&stop);

    // Warm-up phase (500ms+ sustained compute)
    for (int i = 0; i < WARMUP_ITERATIONS; i++) {
        warmup_kernel<<<BLOCKS, THREADS>>>();
        cudaDeviceSynchronize();
    }

    // Measurement phase
    unsigned long long *d_clock_counts;
    float *d_dummy;
    cudaMalloc(&d_clock_counts, 2 * sizeof(unsigned long long));
    cudaMalloc(&d_dummy, sizeof(float));

    float elapsed_ms;
    unsigned long long clock_diffs[MEASURE_ITERATIONS];

    for (int i = 0; i < MEASURE_ITERATIONS; i++) {
        cudaEventRecord(start);
        measure_kernel<<<BLOCKS, THREADS>>>(d_clock_counts, d_dummy);
        cudaEventRecord(stop);
        cudaEventSynchronize(stop);
        cudaEventElapsedTime(&elapsed_ms, start, stop);

        unsigned long long h_clock_counts[2];
        cudaMemcpy(h_clock_counts, d_clock_counts, 2 * sizeof(unsigned long long), cudaMemcpyDeviceToHost);

        clock_diffs[i] = h_clock_counts[1] - h_clock_counts[0];
    }

    // Sort and get median
    std::sort(clock_diffs, clock_diffs + MEASURE_ITERATIONS);
    unsigned long long median_clock_diff = clock_diffs[MEASURE_ITERATIONS / 2];

    // Get elapsed time for median measurement (re-run to get matching elapsed_ms)
    cudaEventRecord(start);
    measure_kernel<<<BLOCKS, THREADS>>>(d_clock_counts, d_dummy);
    cudaEventRecord(stop);
    cudaEventSynchronize(stop);
    cudaEventElapsedTime(&elapsed_ms, start, stop);

    // Calculate frequency in kHz (clock64() returns cycles, elapsed_ms is in milliseconds)
    double frequency_kHz = (median_clock_diff / (elapsed_ms * 1000.0)) * 1000.0;

    // Output only the frequency in kHz as required
    printf("%.0f\n", frequency_kHz);

    cudaFree(d_clock_counts);
    cudaFree(d_dummy);
    cudaEventDestroy(start);
    cudaEventDestroy(stop);

    return 0;
}

