#include <stdio.h>
#include <cuda_runtime.h>

#define THREADS_PER_BLOCK 256
#define NUM_BLOCKS 1024
#define ARRAY_SIZE (256 * 1024 * 1024) // 256MB
#define ITERATIONS 100

__global__ void bandwidth_kernel(float* src, float* dst, int size) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    int stride = blockDim.x * gridDim.x;

    for (int i = idx; i < size / sizeof(float); i += stride) {
        dst[i] = src[i];
    }
}

int main() {
    float *d_src, *d_dst;
    cudaEvent_t start, stop;
    float elapsed_time_ms;

    // Allocate device memory
    cudaMalloc(&d_src, ARRAY_SIZE);
    cudaMalloc(&d_dst, ARRAY_SIZE);

    // Create events
    cudaEventCreate(&start);
    cudaEventCreate(&stop);

    // Warm-up
    bandwidth_kernel<<<NUM_BLOCKS, THREADS_PER_BLOCK>>>(d_src, d_dst, ARRAY_SIZE);
    cudaDeviceSynchronize();

    // Measure
    cudaEventRecord(start);
    for (int i = 0; i < ITERATIONS; i++) {
        bandwidth_kernel<<<NUM_BLOCKS, THREADS_PER_BLOCK>>>(d_src, d_dst, ARRAY_SIZE);
    }
    cudaEventRecord(stop);
    cudaEventSynchronize(stop);
    cudaEventElapsedTime(&elapsed_time_ms, start, stop);

    // Calculate bandwidth in GB/s
    float elapsed_time_s = elapsed_time_ms / 1000.0f;
    float total_bytes = 2.0f * ARRAY_SIZE * ITERATIONS; // read + write
    float bandwidth_GBs = total_bytes / (elapsed_time_s * 1e9f);

    // Calculate theoretical bus width based on A10 specs (6251 MHz memory clock)
    float mem_clock_hz = 6.251e9f;
    float bus_width_bits = (bandwidth_GBs * 8.0f * 1e9f) / mem_clock_hz;

    // Output only the bus width in bits as integer
    printf("%d\n", (int)(bus_width_bits + 0.5f));

    // Cleanup
    cudaFree(d_src);
    cudaFree(d_dst);
    cudaEventDestroy(start);
    cudaEventDestroy(stop);

    return 0;
}

