#include <stdio.h>
#include <stdlib.h>
#include <cuda_runtime.h>

#define THREADS_PER_BLOCK 256
#define NUM_BLOCKS 1024
#define ARRAY_SIZE (1 << 26) // 256MB (64M elements)
#define ITERATIONS 100

__global__ void memory_bandwidth_kernel(float* a, float* b, float* c, int size) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    int stride = blockDim.x * gridDim.x;

    for (int i = idx; i < size; i += stride) {
        // Simple memory-intensive operation (copy)
        c[i] = a[i] + b[i];
    }
}

int main() {
    float *d_a, *d_b, *d_c;
    float *h_a, *h_b, *h_c;
    size_t bytes = ARRAY_SIZE * sizeof(float);

    // Allocate host memory
    h_a = (float*)malloc(bytes);
    h_b = (float*)malloc(bytes);
    h_c = (float*)malloc(bytes);

    // Initialize host arrays
    for (int i = 0; i < ARRAY_SIZE; i++) {
        h_a[i] = 1.0f;
        h_b[i] = 2.0f;
    }

    // Allocate device memory
    cudaMalloc(&d_a, bytes);
    cudaMalloc(&d_b, bytes);
    cudaMalloc(&d_c, bytes);

    // Copy data to device
    cudaMemcpy(d_a, h_a, bytes, cudaMemcpyHostToDevice);
    cudaMemcpy(d_b, h_b, bytes, cudaMemcpyHostToDevice);

    // Warm-up
    for (int i = 0; i < 5; i++) {
        memory_bandwidth_kernel<<<NUM_BLOCKS, THREADS_PER_BLOCK>>>(d_a, d_b, d_c, ARRAY_SIZE);
    }
    cudaDeviceSynchronize();

    // Timing
    cudaEvent_t start, stop;
    cudaEventCreate(&start);
    cudaEventCreate(&stop);

    cudaEventRecord(start);
    for (int i = 0; i < ITERATIONS; i++) {
        memory_bandwidth_kernel<<<NUM_BLOCKS, THREADS_PER_BLOCK>>>(d_a, d_b, d_c, ARRAY_SIZE);
    }
    cudaEventRecord(stop);
    cudaEventSynchronize(stop);

    float milliseconds = 0;
    cudaEventElapsedTime(&milliseconds, start, stop);

    // Calculate bandwidth
    double elapsed_seconds = milliseconds / 1000.0;
    // Each iteration: 2 reads (a,b) and 1 write (c) per element
    double total_bytes = (double)ARRAY_SIZE * sizeof(float) * 3 * ITERATIONS;
    double bandwidth_GBs = total_bytes / (elapsed_seconds * 1e9);

    // Output only the bandwidth percentage (ncu will measure the actual percentage)
    printf("%.4f\n", bandwidth_GBs / 600.0 * 100.0); // A10 has ~600GB/s peak bandwidth

    // Cleanup
    cudaFree(d_a);
    cudaFree(d_b);
    cudaFree(d_c);
    free(h_a);
    free(h_b);
    free(h_c);

    return 0;
}
